import React from "react";
import Icon from "../assets/gem.png";

function Footer() {
  return (
    <footer className="bg-gradient-to-r from-purple-900 via-purple-800 to-purple-700 text-white mt-auto">
      <div className="max-w-7xl mx-auto px-6 py-6 md:py-8 text-center">
        {/* Simple centered copyright */}
        <p className="text-sm md:text-base opacity-90">
          © 2026 GemAnalyzer. All Rights Reserved.
        </p>

        {/* Optional small links (keep it minimal) */}
        <div className="mt-3 flex justify-center gap-6 text-sm">
          <a href="/" className="hover:text-blue-300 transition">Home</a>
          <a href="/about" className="hover:text-blue-300 transition">About</a>
          <a href="/instructions" className="hover:text-blue-300 transition">Instructions</a>
          <a href="/imageuploader" className="hover:text-blue-300 transition">Analyse</a>
        </div>
      </div>
    </footer>
  );
}

export default Footer;
